import{_ as a,o as e,c as n,a0 as s}from"./chunks/framework.CSK6mTG2.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"menu1/为什么使用 Object.prototype.toString.call().md","filePath":"menu1/为什么使用 Object.prototype.toString.call().md"}'),p={name:"menu1/为什么使用 Object.prototype.toString.call().md"};function o(l,t,c,i,r,b){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h3 id="typeof-和-instanceof-判断的问题" tabindex="-1">typeof 和 instanceof 判断的问题 <a class="header-anchor" href="#typeof-和-instanceof-判断的问题" aria-label="Permalink to &quot;typeof 和 instanceof 判断的问题&quot;">​</a></h3><p>使用 <code>typeof</code> 判断基本数据类型（包括 symbol）对 null 或引用类型判断不准确。</p><p>typeof Array //&#39;object&#39;</p><p>typeof Object //&#39;object&#39;</p><p>typeof Date //&#39;object&#39;</p><p>typeof null //&#39;object&#39;</p><p>得到的判断不准确</p><p>使用<code>instanceof</code> 来判断 null，则不把 null 当成 Object ，</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>null instanceof null  //报错 右边要是object</span></span>
<span class="line"><span>null instanceof Object  //false 则不把null当成Object</span></span></code></pre></div><p>instanceof 只能判断引用类型 instanceof 也无法判断准确类型 例如数组 Object</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>console.log([] instanceof Object);//true</span></span>
<span class="line"><span>console.log([] instanceof Array);//true</span></span></code></pre></div><p>对一个变量的类型来进行比较准确的判断使用 <code>Object.prototype.toString.call()</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Object.prototype.toString.call(null) // &quot;[object Null]&quot;</span></span></code></pre></div><h3 id="object-prototype-tostring-call-为什么要加-call" tabindex="-1">Object.prototype.toString.call()为什么要加 call(); <a class="header-anchor" href="#object-prototype-tostring-call-为什么要加-call" aria-label="Permalink to &quot;Object.prototype.toString.call()为什么要加 call();&quot;">​</a></h3><p><strong>Object.prototype.toString 可以返回当前调用者的对象类型。</strong> Object.prototype.toString()会返回[object, [[class]]]的字符串</p><p>其中[[class]]会返回 es 定义的对象类型，包含&quot;Arguments&quot;, “Array”, “Boolean”, “Date”, “Error”, “Function”, “JSON”, “Math”, “Number”, “Object”, “RegExp”, 和 “String”； 再加上 es5 新增加的返回[object Undefined]和[object Null]</p><p>Object.prototype.toString()中，他的调用者永远都是 Object.prototype;所以，在不加 call()情况下，我们的出来的结果永远都是 &#39;[object Object]&#39;</p><p>call(),是为了改变 Object.prototype.toString 这个函数都指向。让 Object.prototype.toString 这个方法指向我们所传入的数据。</p><p>每个数据类，他们都重写了 toString()方法。所以，如果我们拿数据本身去 toString()，是得不到对象类型的。 必须用 Object.prototype.toString</p><p>因为有原型链，找到顶层的原型对象，再去 call 改变 this 指向</p><p><a href="https://juejin.cn/post/7116114617834668062" target="_blank" rel="noreferrer">参考连接</a></p><p>Vue 源码做类型检测时，也很喜欢 typeof，instanceof 和 Array.isArray()。只是在做严格的类型检测时，会使用到 Object.prototype.toString。</p><p>相较于 typeof、instanceof、Array.isArray，Object.prototype.toString.call 更可靠，甚至 null，它都检测出来了</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var _toString = Object.prototype.toString;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  function toRawType (value) {</span></span>
<span class="line"><span>    return _toString.call(value).slice(8, -1)</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /**</span></span>
<span class="line"><span>   * Strict object type check. Only returns true</span></span>
<span class="line"><span>   * for plain JavaScript objects.</span></span>
<span class="line"><span>   */</span></span>
<span class="line"><span>  function isPlainObject (obj) {</span></span>
<span class="line"><span>    return _toString.call(obj) === &#39;[object Object]&#39;</span></span>
<span class="line"><span>  }</span></span></code></pre></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>基本的类型检测用 typeof，引用类型检测用 instanceof，还有专门用于检查是不是数组的 Array.isArray()</p>`,26)])])}const g=a(p,[["render",o]]);export{d as __pageData,g as default};
